package main

import (
	"net/http"
	"os"
)

const baseDir = "./files"

func downloadHandler(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("file")
	if filename == "" {
		http.Error(w, "missing file", 500)
		return
	}
	f, err := os.Open(filename)
	if err != nil {
		http.Error(w, err.Error(), 500)
		return
	}
	defer f.Close()
	// serve file
}
